create extension if not exists pgcrypto;
create table public.organizations(id uuid primary key default gen_random_uuid(),slug text unique not null,name text not null,active boolean default true,created_at timestamptz default now(),updated_at timestamptz default now());
insert into public.organizations(slug,name) values('mugo','Agência Mugô') on conflict(slug) do nothing;
create table public.profiles(id uuid primary key references auth.users(id) on delete cascade,organization_id uuid not null references public.organizations(id),name text,email text,role text not null check(role in('admin','manager','viewer')),active boolean default true,created_at timestamptz default now(),updated_at timestamptz default now());
create table public.clients(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id),company_name text not null,trade_name text,contact_name text,document_number text,email text,phone text,website text,instagram text,segment text,lead_source text,status text not null default 'lead' check(status in('lead','active','inactive','former','archived')),notes text,created_at timestamptz default now(),updated_at timestamptz default now(),created_by uuid references auth.users,updated_by uuid references auth.users);
create table public.proposals(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id),client_id uuid not null references public.clients(id),proposal_number text,title text not null,status text not null default 'draft' check(status in('draft','sent','viewed','negotiating','won','lost','expired','cancelled')),sent_at date,viewed_at timestamptz,negotiation_started_at timestamptz,closed_at timestamptz,lost_at timestamptz,expired_at timestamptz,valid_until date,setup_value numeric(14,2) check(setup_value>=0),monthly_value numeric(14,2) check(monthly_value>=0),total_value numeric(14,2) check(total_value>=0),contract_term_months integer check(contract_term_months>=0),responsible text,lead_source text,lost_reason text,notes text,legacy_id text,created_at timestamptz default now(),updated_at timestamptz default now(),created_by uuid references auth.users,updated_by uuid references auth.users);
create table public.proposal_services(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id),proposal_id uuid not null references public.proposals(id) on delete cascade,service_catalog_id text,service_name text not null,service_category text,billing_type text,quantity numeric check(quantity>=0),unit_price numeric(14,2) check(unit_price>=0),monthly_value numeric(14,2) check(monthly_value>=0),one_time_value numeric(14,2) check(one_time_value>=0),created_at timestamptz default now(),updated_at timestamptz default now());
create table public.contracts(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id),client_id uuid not null references public.clients(id),proposal_id uuid references public.proposals(id),contract_number text,status text not null default 'draft' check(status in('draft','pending_signature','active','expired','terminated','cancelled')),signed boolean default false,signed_at date,start_date date,end_date date,minimum_term_months integer check(minimum_term_months>=0),billing_day integer check(billing_day between 1 and 31),setup_value numeric(14,2) check(setup_value>=0),monthly_value numeric(14,2) check(monthly_value>=0),total_value numeric(14,2) check(total_value>=0),auto_renew boolean default false,renewal_status text,termination_date date,termination_reason text,notes text,legacy_id text,created_at timestamptz default now(),updated_at timestamptz default now(),created_by uuid references auth.users,updated_by uuid references auth.users);
create table public.contract_services(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id),contract_id uuid not null references public.contracts(id) on delete cascade,service_catalog_id text,service_name text not null,service_category text,billing_type text,quantity numeric check(quantity>=0),unit_price numeric(14,2) check(unit_price>=0),monthly_value numeric(14,2) check(monthly_value>=0),one_time_value numeric(14,2) check(one_time_value>=0),created_at timestamptz default now(),updated_at timestamptz default now());
create table public.documents(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id),client_id uuid not null references public.clients(id),proposal_id uuid references public.proposals(id),contract_id uuid references public.contracts(id),document_type text not null check(document_type in('proposal','signed_contract','unsigned_contract','amendment','invoice','other')),file_name text not null,storage_bucket text not null,storage_path text not null,mime_type text,file_size bigint check(file_size>=0),version integer default 1 check(version>0),uploaded_by uuid references auth.users,uploaded_at timestamptz default now(),notes text);
create table public.invoice_installments(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id),client_id uuid not null references public.clients(id),contract_id uuid not null references public.contracts(id),reference_month date not null,installment_number integer not null check(installment_number>0),due_date date not null,amount numeric(14,2) not null check(amount>=0),status text not null default 'draft' check(status in('draft','pending','paid','overdue','cancelled','refunded','failed')),provider text,provider_invoice_id text,idempotency_key text,payment_url text,pix_copy_paste text,boleto_url text,paid_at timestamptz,cancelled_at timestamptz,created_at timestamptz default now(),updated_at timestamptz default now(),unique(organization_id,contract_id,reference_month,installment_number));
create unique index invoice_installments_idempotency on public.invoice_installments(idempotency_key) where idempotency_key is not null;
create table public.payments(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id),installment_id uuid not null references public.invoice_installments(id),provider text,provider_payment_id text,amount numeric(14,2) check(amount>=0),status text,payment_method text,paid_at timestamptz,raw_payload jsonb,created_at timestamptz default now(),updated_at timestamptz default now());
create table public.payment_events(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id),installment_id uuid references public.invoice_installments(id),provider text not null,provider_event_id text not null,event_type text,payload jsonb,processed boolean default false,processed_at timestamptz,error_message text,created_at timestamptz default now(),unique(provider,provider_event_id));
create table public.commercial_events(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id),client_id uuid references public.clients(id),proposal_id uuid references public.proposals(id),contract_id uuid references public.contracts(id),event_type text not null,title text not null,description text,old_value jsonb,new_value jsonb,created_by uuid references auth.users,created_at timestamptz default now());
create index clients_org_company on public.clients(organization_id,company_name);create index clients_org_status on public.clients(organization_id,status);create index clients_org_created on public.clients(organization_id,created_at);create index proposals_org_status on public.proposals(organization_id,status);create index proposals_org_sent on public.proposals(organization_id,sent_at);create index proposals_org_responsible on public.proposals(organization_id,responsible);create index proposals_org_client on public.proposals(organization_id,client_id);create index proposals_org_created on public.proposals(organization_id,created_at);
create or replace function public.set_updated_at() returns trigger language plpgsql set search_path='' as $$begin new.updated_at=now();return new;end$$;
do $$declare t text;begin foreach t in array array['organizations','profiles','clients','proposals','proposal_services','contracts','contract_services','invoice_installments','payments'] loop execute format('create trigger set_updated_at before update on public.%I for each row execute function public.set_updated_at()',t);end loop;end$$;
create or replace function public.current_organization_id() returns uuid language sql stable security definer set search_path='' as $$select organization_id from public.profiles where id=auth.uid() and active=true$$;
create or replace function public.current_user_role() returns text language sql stable security definer set search_path='' as $$select role from public.profiles where id=auth.uid() and active=true$$;
create or replace function public.is_active_user() returns boolean language sql stable security definer set search_path='' as $$select exists(select 1 from public.profiles where id=auth.uid() and active=true)$$;
create or replace function public.is_admin() returns boolean language sql stable as $$select public.current_user_role()='admin'$$;
create or replace function public.can_write() returns boolean language sql stable as $$select public.current_user_role() in('admin','manager')$$;
alter table public.organizations enable row level security;alter table public.profiles enable row level security;alter table public.clients enable row level security;alter table public.proposals enable row level security;alter table public.proposal_services enable row level security;alter table public.contracts enable row level security;alter table public.contract_services enable row level security;alter table public.documents enable row level security;alter table public.invoice_installments enable row level security;alter table public.payments enable row level security;alter table public.payment_events enable row level security;alter table public.commercial_events enable row level security;
create policy organizations_read on public.organizations for select to authenticated using(id=public.current_organization_id());create policy organizations_admin on public.organizations for all to authenticated using(id=public.current_organization_id() and public.is_admin()) with check(id=public.current_organization_id() and public.is_admin());
create policy profiles_read on public.profiles for select to authenticated using(organization_id=public.current_organization_id());create policy profiles_admin on public.profiles for all to authenticated using(organization_id=public.current_organization_id() and public.is_admin()) with check(organization_id=public.current_organization_id() and public.is_admin());
do $$declare t text;begin foreach t in array array['clients','proposals','proposal_services','contracts','contract_services','documents','invoice_installments','commercial_events'] loop execute format('create policy %I_read on public.%I for select to authenticated using(organization_id=public.current_organization_id() and public.is_active_user())',t,t);execute format('create policy %I_write on public.%I for all to authenticated using(organization_id=public.current_organization_id() and public.can_write()) with check(organization_id=public.current_organization_id() and public.can_write())',t,t);end loop;end$$;
create policy payments_admin_manager on public.payments for all to authenticated using(organization_id=public.current_organization_id() and public.can_write()) with check(organization_id=public.current_organization_id() and public.can_write());create policy payments_view_safe on public.payments for select to authenticated using(organization_id=public.current_organization_id() and public.current_user_role() in('admin','manager'));
create policy payment_events_admin_manager on public.payment_events for all to authenticated using(organization_id=public.current_organization_id() and public.can_write()) with check(organization_id=public.current_organization_id() and public.can_write());
insert into storage.buckets(id,name,public,file_size_limit,allowed_mime_types) values('crm-documents','crm-documents',false,10485760,array['application/pdf','application/msword','application/vnd.openxmlformats-officedocument.wordprocessingml.document']) on conflict(id) do update set public=false;
create policy crm_documents_read on storage.objects for select to authenticated using(bucket_id='crm-documents' and (storage.foldername(name))[1]=public.current_organization_id()::text and public.is_active_user());
create policy crm_documents_write on storage.objects for insert to authenticated with check(bucket_id='crm-documents' and (storage.foldername(name))[1]=public.current_organization_id()::text and public.can_write());
create policy crm_documents_update on storage.objects for update to authenticated using(bucket_id='crm-documents' and (storage.foldername(name))[1]=public.current_organization_id()::text and public.can_write()) with check(bucket_id='crm-documents' and (storage.foldername(name))[1]=public.current_organization_id()::text and public.can_write());
create policy crm_documents_delete on storage.objects for delete to authenticated using(bucket_id='crm-documents' and (storage.foldername(name))[1]=public.current_organization_id()::text and public.can_write());
